#include<bits/stdc++.h>
using namespace std;
const int N=100010;
bool vis[N];
vector<pair<int,int>> mp[N];
long long ans;
int dp[N],siz[N],sum,root,dis[N],p[N],tot,n,k;
void getroot(int x,int fa=-1)
{
    siz[x]=1;
    dp[x]=0;
    for(auto i:mp[x])
    {
        int v=i.first;
        if(v!=fa&&!vis[v])
        {
            getroot(v,x);
            siz[x]+=siz[v];
            dp[x]=max(dp[x],siz[v]);
        }
    }
    dp[x]=max(dp[x],sum-siz[x]);
    if(dp[x]<dp[root])
    {
        root=x;
    }
}
void getdis(int x,int fa=-1)
{
    p[++tot]=dis[x];
    for(auto i:mp[x])
    {
        int v=i.first,val=i.second;
        if(v!=fa&&!vis[v])
        {
            dis[v]=dis[x]+val;
            getdis(v,x);
        }
    }
}
int getans(int x,int w)
{
    tot=0;
    dis[x]=w;
    getdis(x,0);
    sort(p+1,p+1+tot);
    int l=1,r=tot,ans=0;
    while(l<=r)
    {
        if(p[l]+p[r]<=k)
        {
            ans+=r-l;
            l++;
        }
        else
        {
            r--;
        }
    }
    return ans;
}
void solve(int x)
{
    vis[x]=true;
    ans+=getans(x,0);
    for(auto i:mp[x])
    {
        int v=i.first,val=i.second;
        if(!vis[v])
        {
            ans-=getans(v,val);
            sum=siz[v];
            dp[0]=n;
            root=0;
            getroot(v,x);
            solve(v);
        }
    }
}
int main()
{
    scanf("%d",&n);
    for(int i=1;i<n;i++)
    {
        int u,v,w;
        scanf("%d%d%d",&u,&v,&w);
        mp[u].push_back({v,w});
        mp[v].push_back({u,w});
    }
    scanf("%d",&k);
    dp[0]=sum=n;
    getroot(1);
    solve(root);
    printf("%lld",ans);
    return 0;
}
